import{_ as e,o as s,c as n,O as t}from"./chunks/framework.0d5b6918.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/product/implementation-training.md","filePath":"en/product/implementation-training.md","lastUpdated":1776439080000}'),i={name:"en/product/implementation-training.md"};function r(l,a,p,o,d,c){return s(),n("div",null,a[0]||(a[0]=[t('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Implementation &amp; Training Services</p><h1>Implementation &amp; Training Services Services</h1><div class="brand-hero__panel"><span class="brand-pill">Implementation Scope</span><strong>ExecFabric does not only provide a software opening. The current delivery path also includes scoped configuration, role-based training, and handoff support within the agreed project range.</strong><p>The point is not to walk through pages one by one. The point is to explain scope, onboarding, usage, acceptance, and support boundaries clearly in one place.</p></div><p class="brand-lead"> For most customers, four questions matter first: <strong>what the implementation steps are, which roles need training, which notes are handed over, and where ongoing support stops.</strong></p><div class="brand-chip-list"><span class="brand-chip">Scope alignment</span><span class="brand-chip">Deployment setup</span><span class="brand-chip">Role-based training</span><span class="brand-chip">Go-live support</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="/en/contact.html#lead-form">Discuss the implementation plan</a><a class="cta-button" href="./deliverables.html">View deliverables</a><a class="cta-button" href="../materials/service-packages.html">View service packages</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // IMPLEMENTATION</span><span>DOC 11</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">implementationSteps</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;scope&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;deploy&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;onboard&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;accept&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">trainingTargets</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;owner&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;tenant_admin&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;users&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;it_ops&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">supportWindow</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;workday_support&#39;</span></span></div><div class="matrix-panel__callout">TRAIN THE RIGHT ROLE, NOT EVERYONE AT ONCE</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">delivery</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">guided</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">training</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">role-based</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">support</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">bounded</span></span></div></div></div></section><section class="brand-card"><p class="brand-kicker">Implementation Steps</p><h2>Standard implementation steps</h2><table><thead><tr><th>Phase</th><th>What happens</th><th>Current focus</th></tr></thead><tbody><tr><td>01. Scope confirmation</td><td>Confirm the core scenario, the first capability batch, the delivery boundary, and the out-of-scope items</td><td>Keep phase one small and real instead of opening with an oversized platform story</td></tr><tr><td>02. Environment preparation</td><td>Decide whether the project is team edition, lightweight private deployment, or standard private deployment, then prepare access entries, accounts, and deployment conditions</td><td>Clarify the deployment mode and delivery mode early instead of mixing them together</td></tr><tr><td>03. Capability onboarding</td><td>Bring in the customer&#39;s existing scripts, flows, or result chains and configure permissions plus execution entries</td><td>Run the smallest closed loop first, then consider second-stage expansion</td></tr><tr><td>04. Joint testing and acceptance</td><td>Test the key chains together, align the acceptance items, and close issues that are inside the agreed delivery range</td><td>Make sure the customer can say it is usable, understandable, and sustainable after go-live</td></tr><tr><td>05. Training and go-live</td><td>Train by role, hand over notes, and explain support boundaries plus the future update path</td><td>Go-live is not the end. It is the point where sustained usage begins</td></tr></tbody></table></section><section class="brand-grid brand-grid--four"><article class="brand-card"><p class="brand-kicker">Role 01</p><h2>Business owner</h2><p>Training focuses on what problem the platform solves, what the current boundary is, and when the work should move into the next phase.</p></article><article class="brand-card"><p class="brand-kicker">Role 02</p><h2>Tenant administrator</h2><p>Training focuses on how to log in, where capabilities are visible, where execution records are visible, and how to submit update or expansion requests.</p></article><article class="brand-card"><p class="brand-kicker">Role 03</p><h2>General users</h2><p>Training focuses on how to trigger capabilities through pages or the intelligent assistant, view results, upload files, and download output artifacts.</p></article><article class="brand-card"><p class="brand-kicker">Role 04</p><h2>Client IT / operations</h2><p>For private deployment, training focuses on the deployment form, runtime requirements, backup and recovery, and the local environment boundary.</p></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Standard Handoff</p><h2>Current standard handoff items</h2><ul class="brand-list"><li>Platform access entry</li><li>Initial accounts and initialization method</li><li>Customer delivery notes</li><li>Customer usage notes</li><li>Customer-facing capability notes</li><li>Customer script hot-update notes</li><li>If included in the project, notes for file upload and result download chains</li><li>If included in the project, the customer notice entry or related documents</li></ul></article><article class="brand-card"><p class="brand-kicker">Client Preparation</p><h2>What is useful to prepare before implementation</h2><ul class="brand-list"><li>Core scenario list</li><li>Scripts or flows to onboard first</li><li>The roles that should attend training</li><li>If independent deployment is needed, server and network conditions confirmed in advance</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Support Boundary</p><h2>Current support boundary</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>Included by default</h3><ul class="brand-list"><li>Troubleshooting for issues inside the delivered scope</li><li>Answers to baseline usage questions</li><li>A small amount of script updates or configuration help</li><li>Platform runtime assistance</li></ul></article><article class="brand-card brand-card--nested"><h3>Not included by default</h3><ul class="brand-list"><li>New feature development</li><li>Large-scale page redesign</li><li>Deep third-party system integration</li><li>Resident service, high-SLA operations, or long-duration embedded support</li></ul></article></div><p class="brand-lead"> If baseline support is included, the current default assumption is <strong>workdays `09:00-18:00` with ticket, email, or WeCom as the main channels.</strong> Higher response levels or longer support windows should be agreed separately. </p></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>Continue with delivery boundaries, deployment options, and service packages</h2><p class="brand-lead">If you are already moving into a formal discussion, the next useful step is to review deliverables, deployment mode, and cooperation path together.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./deliverables.html"><span>Customer Delivery Docs &amp; Entry Points</span><strong>Customer Delivery Docs &amp; Entry Points</strong></a><a class="brand-link-card" href="./deployment.html"><span>Deployment &amp; Delivery Boundaries</span><strong>Deployment &amp; Delivery Boundaries</strong></a><a class="brand-link-card" href="../materials/service-packages.html"><span>Packages</span><strong>Service Packages</strong></a><a class="brand-link-card" href="/en/contact.html#lead-form"><span>Contact</span><strong>Discuss implementation</strong></a></div></div></section></div>',1)]))}const h=e(i,[["render",r]]);export{u as __pageData,h as default};
